#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Category distribution for the Neural Map (read-only, exit-0-safe). Publishes real
counts per category for total(1.8M), website(625k), prospects(qa PASS ~13k), + icp_tier
and region mix -> status/hetzner/catdist.json."""
import os,sys,json,time,subprocess,base64,urllib.request,urllib.error
def psql(q):
    for runner in (["sudo","-u","postgres","psql","tuanichat_atlas","-tAF|","-c",q],
                   ["su","-s","/bin/sh","postgres","-c","psql tuanichat_atlas -tAF'|' -c \"%s\""%q.replace('"','\\"')]):
        try:
            r=subprocess.run(runner,capture_output=True,text=True,timeout=60)
            if r.returncode==0: return r.stdout.strip()
        except Exception: pass
    return "ERR"
out={"kind":"catdist","ts":int(time.time())}
try:
    out["totals"]=psql("SELECT count(*), count(*) FILTER (WHERE website IS NOT NULL AND website<>''), count(*) FILTER (WHERE email IS NOT NULL AND email<>''), count(*) FILTER (WHERE qa_status='PASS') FROM atlas.business")
    out["top_categories"]=psql("SELECT coalesce(nullif(trim(category),''),'(uncategorized)') c, count(*) t, count(*) FILTER (WHERE website IS NOT NULL AND website<>'') w, count(*) FILTER (WHERE qa_status='PASS') p FROM atlas.business GROUP BY 1 ORDER BY t DESC LIMIT 45")
    out["icp_tier"]=psql("SELECT coalesce(icp_tier,'(none)'), count(*) FROM atlas.business GROUP BY 1 ORDER BY 2 DESC")
    out["prospect_categories"]=psql("SELECT coalesce(nullif(trim(category),''),'(uncategorized)') c, count(*) p FROM atlas.business WHERE qa_status='PASS' GROUP BY 1 ORDER BY p DESC LIMIT 30")
    out["regions"]=psql("SELECT coalesce(nullif(trim(region),''),'(none)') r, count(*) FROM atlas.business GROUP BY 1 ORDER BY 2 DESC LIMIT 20")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    env=envf("/etc/atlas/autopull.env")
    tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN")
    repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    br=env.get("STATUS_BRANCH","main"); api="https://api.github.com"; path="status/hetzner/catdist.json"
    if tok and repo:
        url="%s/repos/%s/contents/%s"%(api,repo,path); sha=None
        try:
            r=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"})
            sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"catdist","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":br}
        if sha: body["sha"]=sha
        for _ in range(4):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"})
                urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"})
                        body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
